"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[63250],{69228:(e,n,i)=>{i.r(n),i.d(n,{data:()=>l});const l={key:"v-e58cf6d2",path:"/GDAL/gdal%E4%B8%AD%E6%96%87%E4%B9%B1%E7%A0%81.html",title:"中文乱码",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"1.读取中文乱码",slug:"_1-读取中文乱码",children:[]},{level:3,title:"2.写入中文乱码",slug:"_2-写入中文乱码",children:[]}],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"GDAL/gdal中文乱码.md"}},50835:(e,n,i)=>{i.r(n),i.d(n,{default:()=>t});const l=(0,i(57293).uE)('<h1 id="中文乱码" tabindex="-1"><a class="header-anchor" href="#中文乱码" aria-hidden="true">#</a> 中文乱码</h1><h3 id="_1-读取中文乱码" tabindex="-1"><a class="header-anchor" href="#_1-读取中文乱码" aria-hidden="true">#</a> 1.读取中文乱码</h3><p>全局环境设置</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>gdal.SetConfigOption(&quot;GDAL_FILENAME_IS_UTF8&quot;, &quot;YES&quot;);  //中文路径\ngdal.SetConfigOption(&quot;SHAPE_ENCODING&quot;, &quot;&quot;);//读取时使用文件默认编码\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>读取属性(<code>IdentifyEncoding</code>是根据字节数组判断编码名称的类)</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>        [DllImport(&quot;gdal204.dll&quot;, EntryPoint = &quot;OGR_F_GetFieldAsString&quot;, CallingConvention = CallingConvention.Cdecl)]\n        public extern static System.IntPtr OGR_F_GetFieldAsString(HandleRef handle, int i);\n\n        [DllImport(&quot;gdal204.dll&quot;, EntryPoint = &quot;OGR_F_GetFieldAsBinary&quot;, CallingConvention = CallingConvention.Cdecl)]\n        public extern static System.IntPtr OGR_F_GetFieldAsBinary(HandleRef handle, int index, out int byteCount);\n\n\n        \n        /// &lt;summary&gt;\n        /// 读取属性\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;poFeature&quot;&gt;要素&lt;/param&gt;\n        /// &lt;param name=&quot;fieldIndex&quot;&gt;字段索引&lt;/param&gt;\n        /// &lt;param name=&quot;encodingName&quot;&gt;编码名称&lt;/param&gt;\n        /// &lt;returns&gt;属性值&lt;/returns&gt;\n        public static object GetFieldValue(Feature poFeature, int fieldIndex, string encodingName = &quot;&quot;)\n        {\n            FieldType Ftype = poFeature.GetFieldType(fieldIndex);\n            object fieldValue;\n            switch (Ftype)\n            {\n                case FieldType.OFTString:\n\n                    int byteCount = 0;\n                    IntPtr pIntPtr = OGR_F_GetFieldAsBinary(OSGeo.OGR.Feature.getCPtr(poFeature), fieldIndex, out byteCount);\n                    if (byteCount == 0)\n                    {\n                        return &quot;&quot;;\n                    }\n                    byte[] byteArray = new byte[byteCount];\n                    Marshal.Copy(pIntPtr, byteArray, 0, byteCount);\n\n                    //当没有指定编码名称时根据文件流判断编码名称\n                    if (string.IsNullOrEmpty(encodingName))\n                    {\n                        sbyte[] sbytes = new sbyte[byteCount];\n                        for (int i = 0; i &lt; byteCount; i++)\n                        {\n                            sbytes[i] = (sbyte)byteArray[i];\n                        }\n                        encodingName = new IdentifyEncoding().GetEncodingName(sbytes);\n                    }\n                    fieldValue = System.Text.Encoding.GetEncoding(encodingName).GetString(byteArray);\n\n\n                    break;\n                case FieldType.OFTReal:\n                    fieldValue = poFeature.GetFieldAsDouble(fieldIndex);\n                    break;\n                case FieldType.OFTInteger:\n                    fieldValue = poFeature.GetFieldAsInteger(fieldIndex);\n                    break;\n                default:\n                    fieldValue = poFeature.GetFieldAsString(fieldIndex);\n                    break;\n            }\n\n            return fieldValue;\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-写入中文乱码" tabindex="-1"><a class="header-anchor" href="#_2-写入中文乱码" aria-hidden="true">#</a> 2.写入中文乱码</h3><p>全局环境设置</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>gdal.SetConfigOption(&quot;GDAL_FILENAME_IS_UTF8&quot;, &quot;YES&quot;);  //中文路径\ngdal.SetConfigOption(&quot;SHAPE_ENCODING&quot;, &quot;CP936&quot;);//中文属性\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>',9),d={},t=(0,i(63243).Z)(d,[["render",function(e,n){return l}]])},63243:(e,n)=>{n.Z=(e,n)=>{const i=e.__vccOpts||e;for(const[e,l]of n)i[e]=l;return i}}}]);